import React from 'react';
import optImg from '../assets/opt.JPG';

const Home = () => {
    return (
        <div className="flex flex-col items-center justify-center min-h-screen bg-gradient-to-br from-blue-100 via-white to-blue-300">
            {/* Profile Image */}
            <img
                src={optImg}
                alt="Profile"
                className="w-44 h-44 rounded-full mb-8 shadow-2xl border-8 border-blue-400"
            />
            {/* About Me Section */}
            <h1 className="text-6xl font-extrabold mb-6 text-blue-700 drop-shadow-lg">Welcome to My Portfolio</h1>
            <div className="bg-white rounded-2xl shadow-2xl p-8 mb-8 max-w-xl border border-blue-200">
                <p className="text-xl text-center">
                    <span className="font-semibold text-blue-600 text-2xl">About Me:</span> <br />
                    Hi, I'm Veera! I am a passionate developer with experience in JavaScript, React, Tailwind CSS, and Node.js. I love building modern web applications and learning new technologies.
                </p>
            </div>
            <h2 className="text-3xl font-bold mb-3 text-blue-600 drop-shadow">Skills:</h2>
            <ul className="list-disc list-inside mb-10 text-xl text-blue-800">
                <li>JavaScript</li>
                <li>React</li>
                <li>Tailwind CSS</li>
                <li>Node.js</li>
            </ul>
            <h2 className="text-3xl font-bold mb-3 text-blue-600 drop-shadow">Projects:</h2>
            <p className="mb-6 text-lg text-blue-700">Check out some of my projects below:</p>
            <a href="/projects" className="text-blue-500 hover:underline font-semibold text-xl transition duration-200 hover:text-blue-700">View Projects</a>
        </div>
    );
};

export default Home;
